CREATE TABLE IF NOT EXISTS fare_rules(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),ride_type text NOT NULL,scope text NOT NULL DEFAULT 'LOCAL',config jsonb NOT NULL,active boolean NOT NULL DEFAULT true,valid_from timestamptz NOT NULL DEFAULT now(),valid_to timestamptz);
CREATE TABLE IF NOT EXISTS service_zones(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),name text NOT NULL,zone_type text NOT NULL,polygon_geojson jsonb NOT NULL,high_risk boolean NOT NULL DEFAULT false,dynamic_pricing_enabled boolean NOT NULL DEFAULT false,active boolean NOT NULL DEFAULT true);
CREATE TABLE IF NOT EXISTS promoter_profiles(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),role text NOT NULL CHECK(role IN('PROMOTER','AREA_PROMOTER')),name text NOT NULL,mobile text NOT NULL UNIQUE,status text NOT NULL DEFAULT 'ACTIVE',area_promoter_id uuid REFERENCES promoter_profiles(id),created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS promoter_driver_links(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),promoter_id uuid REFERENCES promoter_profiles(id),area_promoter_id uuid REFERENCES promoter_profiles(id),driver_id uuid NOT NULL UNIQUE,created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS promoter_coaching_logs(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),promoter_id uuid REFERENCES promoter_profiles(id),area_promoter_id uuid REFERENCES promoter_profiles(id),driver_id uuid NOT NULL,action_type text NOT NULL,note text NOT NULL,created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS promoter_earnings(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),beneficiary_id uuid REFERENCES promoter_profiles(id),booking_id uuid NOT NULL,month text NOT NULL,amount numeric(12,2) NOT NULL,status text NOT NULL DEFAULT 'PENDING_MONTH_CLOSE',created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS late_arrival_cases(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),booking_id uuid NOT NULL,committed_arrival_at timestamptz NOT NULL,actual_arrival_at timestamptz,late_minutes integer NOT NULL DEFAULT 0,penalty numeric(12,2) NOT NULL DEFAULT 0,status text NOT NULL,reason text,created_at timestamptz NOT NULL DEFAULT now());
